**Email/Parola Giriş:**
```dart
Future<UserCredential?> signInWithEmail(String email, String password) async {
  try {
    return await FirebaseAuth.instance.signInWithEmailAndPassword(
      email: email.trim(),
      password: password,
    );
  } on FirebaseAuthException catch (e) {
    // Hata kodları: user-not-found, wrong-password, too-many-requests
    throw _mapFirebaseError(e.code);
  }
}

String _mapFirebaseError(String code) {
  const errors = {
    'user-not-found': 'Kullanıcı bulunamadı',
    'wrong-password': 'Hatalı şifre',
    'too-many-requests': 'Çok fazla deneme, lütfen bekleyin'
  };
  return errors[code] ?? 'Giriş başarısız';
}
```

